const imageRegex = /\.(jpg|jpeg|png|webp)$/i;
const keywordRegex = /Android|Galaxy/i;

for (const item of $input.all()) {
  if(!imageRegex.test(item.json.img)){
   item.json.img = "" 
  }
  if(!keywordRegex.test(item.json.title)){
    item.json.title = ""
  }
}

return $input.all();

const articles = $('Check for Required Fields').all();
const guids = $('getPulishedLinkedInPostIDs').first().json.guids;
const filtered = [];

articles.forEach((article) => {
  if(!guids.includes(article.json.guid)){
    filtered.push(article)
  }
});

return filtered;

